class Playground {
  async run(inputs) {
    const arr = inputs[0].split(',').map(x => x.trim());
    this.array.init(arr);
    this.log('Reverse array using Two Pointers technique');
    await this.await();

    let left = 0;
    let right = arr.length - 1;

    this.ptr.set('left', left);
    this.ptr.set('right', right);
    this.log(`Initialize pointers: left=${left}, right=${right}`);
    await this.await();

    while (left < right) {
      this.array.highlight(left, '#3b82f6');
      this.array.highlight(right, '#3b82f6');
      this.log(`Compare: arr[${left}]='${arr[left]}' and arr[${right}]='${arr[right]}'`);
      await this.await();

      this.array.highlight(left, '#f59e0b');
      this.array.highlight(right, '#f59e0b');
      this.log(`Swapping '${arr[left]}' ↔ '${arr[right]}'`);
      await this.await();

      [arr[left], arr[right]] = [arr[right], arr[left]];
      this.array.swap(left, right);

      this.array.highlight(left, '#10b981');
      this.array.highlight(right, '#10b981');
      this.log('✓ Swapped!');
      await this.await();

      left++;
      right--;
      this.ptr.set('left', left);
      this.ptr.set('right', right);
      this.array.clearHighlights();

      if (left < right) {
        this.log(`Move pointers: left=${left}, right=${right}`);
        await this.await();
      }
    }

    this.ptr.remove('left');
    this.ptr.remove('right');
    this.log('✅ Array reversed!');
    await this.await();
    return arr.join(', ');
  }
}
